import React, { useEffect, useState, useContext } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext'; // nếu bạn dùng context
// If you don't have AuthContext, we'll fall back to localStorage token

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const AddProduct = () => {
  const navigate = useNavigate();
  const { user, logout } = useContext(AuthContext || {});
  const [categories, setCategories] = useState([]);
  const [loadingCategories, setLoadingCategories] = useState(true);

  const [name, setName] = useState('');
  const [flowerType, setFlowerType] = useState('');
  const [season, setSeason] = useState('Quanh năm');
  const [categoryId, setCategoryId] = useState('');
  const [price, setPrice] = useState('');
  const [discountPrice, setDiscountPrice] = useState('');
  const [stock, setStock] = useState(0);
  const [isFeatured, setIsFeatured] = useState(false);
  const [tagsInput, setTagsInput] = useState('');
  const [tags, setTags] = useState([]);
  const [description, setDescription] = useState('');

  // images
  const [files, setFiles] = useState([]); // File objects
  const [previews, setPreviews] = useState([]); // data-URLs for preview

  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  // load categories
  useEffect(() => {
    const fetchCats = async () => {
      try {
        setLoadingCategories(true);
        const res = await axios.get(`${API_URL}/api/categories`);
        // Expect res.data to be array or { categories: [...] } depending on backend
        const cats = Array.isArray(res.data) ? res.data : res.data.categories || res.data.data || [];
        setCategories(cats);
        if (cats.length) setCategoryId(cats[0]._id || cats[0].id || '');
      } catch (err) {
        console.error('Load categories error', err);
      } finally {
        setLoadingCategories(false);
      }
    };
    fetchCats();
  }, []);

  // handle file selection + preview
  useEffect(() => {
    if (!files || files.length === 0) {
      setPreviews([]);
      return;
    }
    const newPreviews = [];
    files.forEach(file => {
      const reader = new FileReader();
      reader.onload = (e) => {
        setPreviews(prev => [...prev, e.target.result]);
      };
      reader.readAsDataURL(file);
    });
    // clear previews first (we append as each file loads)
    setPreviews([]);
    // cleanup not strictly required here
  }, [files]);

  // handle tag parsing (split by comma)
  useEffect(() => {
    const arr = tagsInput
      .split(',')
      .map(t => t.trim())
      .filter(t => t.length > 0);
    setTags(arr);
  }, [tagsInput]);

  const handleFilesChange = (e) => {
    const chosen = Array.from(e.target.files || []);
    // Optionally validate file types/sizes here
    setFiles(chosen);
  };

  const removePreviewAt = (index) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const getToken = () => {
    try {
      const ctxToken = user?.token;
      if (ctxToken) return ctxToken;
      const info = JSON.parse(localStorage.getItem('userInfo'));
      return info?.token;
    } catch (err) {
      return null;
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (!name || !categoryId || !price || !description) {
      setError('Vui lòng điền đầy đủ các trường có dấu *');
      return;
    }

    const token = getToken();
    if (!token) {
      alert('Bạn chưa đăng nhập hoặc phiên hết hạn. Vui lòng đăng nhập lại.');
      if (logout) logout();
      return;
    }

    try {
      setSubmitting(true);

      // build FormData
      const form = new FormData();
      form.append('name', name);
      form.append('description', description);
      form.append('price', Number(price));
      if (discountPrice) form.append('discountPrice', Number(discountPrice));
      form.append('categoryId', categoryId);
      form.append('flowerType', flowerType);
      form.append('season', season);
      form.append('stock', Number(stock));
      form.append('isFeatured', isFeatured ? 'true' : 'false');
      // tags as CSV or array — backend handles both; we append as comma string
      if (tags.length) form.append('tags', tags.join(','));
      // append files
      files.forEach((file) => {
        form.append('images', file); // name 'images' matches upload.array('images', 5)
      });

      // POST
      // If your backend admin route is /api/admin/products change the url below
      const url = `${API_URL}/api/products`; // <-- change to /api/admin/products if needed
      const res = await axios.post(url, form, {
        headers: {
          'Content-Type': 'multipart/form-data',
          Authorization: `Bearer ${token}`
        },
        timeout: 120000
      });

      // success -> redirect to products list
      alert('Thêm sản phẩm thành công!');
      navigate('/admin/products');
    } catch (err) {
      console.error('Add product error', err);
      const msg = err?.response?.data?.message || err?.response?.data?.error || err.message || 'Lỗi khi thêm sản phẩm';
      setError(msg);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <div className="max-w-4xl mx-auto bg-white p-6 rounded shadow">
        <h2 className="text-2xl font-semibold mb-4">Thêm sản phẩm mới</h2>

        {error && <div className="mb-4 text-red-700 bg-red-100 p-3 rounded">{error}</div>}

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Tên sản phẩm *</label>
              <input value={name} onChange={e => setName(e.target.value)} className="w-full border px-3 py-2 rounded" />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Danh mục *</label>
              <select value={categoryId} onChange={e => setCategoryId(e.target.value)} className="w-full border px-3 py-2 rounded">
                {loadingCategories ? <option>Đang tải...</option> : categories.length ? (
                  categories.map(c => <option key={c._id || c.id} value={c._id || c.id}>{c.name}</option>)
                ) : <option>Không có danh mục</option>}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Giá gốc (VNĐ) *</label>
              <input type="number" min="0" value={price} onChange={e => setPrice(e.target.value)} className="w-full border px-3 py-2 rounded" />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Giá khuyến mãi (VNĐ)</label>
              <input type="number" min="0" value={discountPrice} onChange={e => setDiscountPrice(e.target.value)} className="w-full border px-3 py-2 rounded" />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Tồn kho</label>
              <input type="number" min="0" value={stock} onChange={e => setStock(e.target.value)} className="w-full border px-3 py-2 rounded" />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Loại hoa</label>
              <input value={flowerType} onChange={e => setFlowerType(e.target.value)} className="w-full border px-3 py-2 rounded" />
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Mùa</label>
              <select value={season} onChange={e => setSeason(e.target.value)} className="w-full border px-3 py-2 rounded">
                <option>Quanh năm</option>
                <option>Xuân</option>
                <option>Hạ</option>
                <option>Thu</option>
                <option>Đông</option>
              </select>
            </div>

            <div className="col-span-2">
              <label className="block text-sm font-medium mb-1">Tags (ngăn cách bằng dấu phẩy)</label>
              <input value={tagsInput} onChange={e => setTagsInput(e.target.value)} placeholder="ví dụ: quà tặng, sinh nhật, tình yêu" className="w-full border px-3 py-2 rounded" />
              {tags.length > 0 && (
                <div className="mt-2 flex flex-wrap gap-2">
                  {tags.map((t, i) => (
                    <div key={i} className="text-sm bg-gray-100 px-2 py-1 rounded">{t}</div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">Mô tả *</label>
            <textarea value={description} onChange={e => setDescription(e.target.value)} rows="6" className="w-full border px-3 py-2 rounded" />
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">Hình ảnh (tối đa 5 ảnh)</label>
            <input type="file" accept="image/*" multiple onChange={handleFilesChange} className="block" />
            {previews.length > 0 && (
              <div className="mt-3 grid grid-cols-5 gap-2">
                {previews.map((p, idx) => (
                  <div key={idx} className="relative">
                    <img src={p} alt={`preview-${idx}`} className="w-28 h-28 object-cover rounded border" />
                    <button type="button" onClick={() => removePreviewAt(idx)} className="absolute top-0 right-0 bg-white rounded-full p-1 text-red-600 shadow">✕</button>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="flex items-center gap-4">
            <label className="inline-flex items-center gap-2">
              <input type="checkbox" checked={isFeatured} onChange={e => setIsFeatured(e.target.checked)} />
              <span>Sản phẩm nổi bật</span>
            </label>
          </div>

          <div className="flex gap-3">
            <button type="submit" disabled={submitting} className="bg-green-700 text-white px-4 py-2 rounded">
              {submitting ? 'Đang lưu...' : 'Thêm sản phẩm'}
            </button>
            <button type="button" onClick={() => navigate('/admin/products')} className="bg-gray-200 px-4 py-2 rounded">
              Hủy
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddProduct;
